// Exemplo conceitual (browser): separar camadas por contrato

// Camada runtime/plataforma: rede (fetch) + política (CORS etc.)
async function obterUsuarios() {
  const res = await fetch("/api/users");
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
}

// Camada linguagem: transformação pura (testável)
function paraLista(usuarios) {
  return usuarios.map(u => `${u.id} — ${u.name}`);
}

// Camada runtime (DOM): efeitos colaterais (UI)
function renderizarLista(itens) {
  const ul = document.querySelector("#users");
  ul.innerHTML = itens.map(t => `<li>${t}</li>`).join("");
}

// Orquestração: fluxo
obterUsuarios()
  .then(paraLista)
  .then(renderizarLista)
  .catch(err => console.error("Falha", err));
